import{_ as n,o as t,c as a,a2 as i}from"./chunks/framework.Bix3-HpO.js";const k=JSON.parse('{"title":"Managing Links","description":"Creating and Managing Redirect Links in Nonaki","frontmatter":{"title":"Managing Links","description":"Creating and Managing Redirect Links in Nonaki","weight":20,"extra":{"order":20},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/nonaki/links"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/nonaki/links"}],["meta",{"property":"og:title","content":"Managing Links"}],["meta",{"property":"og:description","content":"Creating and Managing Redirect Links in Nonaki"}],["meta",{"name":"twitter:title","content":"Managing Links"}],["meta",{"name":"twitter:description","content":"Creating and Managing Redirect Links in Nonaki"}]]},"headers":[],"relativePath":"docs/nonaki/links.md","filePath":"docs/nonaki/links.md"}'),o={name:"docs/nonaki/links.md"};function r(s,e,l,d,c,g){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="managing-links" tabindex="-1">Managing Links <a class="header-anchor" href="#managing-links" aria-label="Permalink to &quot;Managing Links&quot;">​</a></h1><p>Nonaki turns long or ugly URLs into clean redirect links on your own domain. All links are managed from the <strong>Nonaki Links</strong> section in your WordPress dashboard.</p><hr><h2 id="redirect-slug" tabindex="-1">Redirect Slug <a class="header-anchor" href="#redirect-slug" aria-label="Permalink to &quot;Redirect Slug&quot;">​</a></h2><p>The redirect slug is the base path that appears in all your links. The default is <code>links</code>, producing URLs like <code>yoursite.com/links/your-key</code>. You can change it in <a href="/docs/nonaki/settings"><strong>Settings</strong></a> at any time.</p><hr><h2 id="creating-a-link" tabindex="-1">Creating a Link <a class="header-anchor" href="#creating-a-link" aria-label="Permalink to &quot;Creating a Link&quot;">​</a></h2><p>Click <code>Add New</code> to open the create form. You need two things:</p><ul><li><strong>Link Key</strong> — the short identifier that appears in the URL (e.g. <code>dinomatic</code>). Letters, numbers, hyphens, and underscores are allowed.</li><li><strong>Destination URL</strong> — the full URL visitors are sent to.</li></ul><p>You can also set the <strong>Redirect Type</strong>:</p><ul><li><code>301</code> — Moved Permanently (default; best for SEO and affiliate links)</li><li><code>302</code> — Found (temporary redirect)</li><li><code>307</code> — Temporary Redirect (preserves the HTTP method)</li></ul><p>Once saved, the full redirect URL is shown in the links list and can be copied with one click.</p><hr><h2 id="managing-links-1" tabindex="-1">Managing Links <a class="header-anchor" href="#managing-links-1" aria-label="Permalink to &quot;Managing Links&quot;">​</a></h2><p>All links are listed in the <strong>Links</strong> view with the following options:</p><ul><li><strong>Search</strong> — filter by link key or destination URL</li><li><strong>Tag filter</strong> — show only links with a specific tag</li><li><strong>Edit</strong> — update the destination URL, link key, or redirect type</li><li><strong>Copy</strong> — copy the full redirect URL to the clipboard</li><li><strong>Trash</strong> — move the link to trash (stops the redirect immediately)</li></ul><h3 id="broken-link-badge" tabindex="-1">Broken Link Badge <a class="header-anchor" href="#broken-link-badge" aria-label="Permalink to &quot;Broken Link Badge&quot;">​</a></h3><p>If the link checker detects that a destination URL is unreachable, the link row displays a <code>broken</code> badge. See <a href="/docs/nonaki/link-checker">Link Checker</a> for details.</p><hr><h2 id="tags" tabindex="-1">Tags <a class="header-anchor" href="#tags" aria-label="Permalink to &quot;Tags&quot;">​</a></h2><p>Tags help you organize links into groups. You can create and manage tags from the <strong>Tags</strong> section, then assign one or more tags to any link.</p><p>The links list can be filtered by tag to quickly find a subset of your links.</p><hr><h2 id="trash" tabindex="-1">Trash <a class="header-anchor" href="#trash" aria-label="Permalink to &quot;Trash&quot;">​</a></h2><p>Trashed links no longer redirect visitors but are kept in the database. Visit the <strong>Trash</strong> tab to:</p><ul><li><strong>Restore</strong> — return a link to active status</li><li><strong>Force Delete</strong> — permanently remove the link and all associated analytics data</li></ul><hr><h2 id="bulk-actions" tabindex="-1">Bulk Actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk Actions&quot;">​</a></h2><p>Select multiple links using the checkboxes to apply bulk actions:</p><ul><li><strong>Trash selected</strong></li><li><strong>Restore selected</strong> (Trash view)</li><li><strong>Permanently delete selected</strong> (Trash view)</li></ul>',30)])])}const u=n(o,[["render",r]]);export{k as __pageData,u as default};
